import { useEffect, useRef } from 'react';
import MessageBubble from './MessageBubble';
import WelcomeScreen from './WelcomeScreen';

export default function ChatThread({ messages, stage, onSampleClick }) {
  const bottomRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, stage]);

  if (messages.length === 0) {
    return (
      <div style={{ flex: 1, overflowY: 'auto' }}>
        <WelcomeScreen onSampleClick={onSampleClick} />
      </div>
    );
  }

  // Find if the last message is a loading assistant message
  const lastMsg = messages[messages.length - 1];
  const loadingMsgId = lastMsg?.loading ? lastMsg.id : null;

  return (
    <div style={{
      flex: 1, overflowY: 'auto',
      paddingTop: 24, paddingBottom: 120,
    }}>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>
        {messages.map(msg => (
          <MessageBubble
            key={msg.id}
            message={msg}
            stage={msg.id === loadingMsgId ? stage : -1}
          />
        ))}
      </div>
      <div ref={bottomRef} />
    </div>
  );
}
